import type { Account } from './account-model';

export const OpportunityConfidencetrendKeyToLabel = {
  'ConfidencetrendKey0': 'up',
  'ConfidencetrendKey1': 'down',
  'ConfidencetrendKey2': 'flat'
} as const;

export const OpportunityStageKeyToLabel = {
  'StageKey0': 'prospecting',
  'StageKey1': 'qualification',
  'StageKey2': 'proposal',
  'StageKey3': 'negotiation',
  'StageKey4': 'won',
  'StageKey5': 'lost'
} as const;

export interface Opportunity {
  /**
   * @displayName Opportunity
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  name1: string;
  /**
   * @displayName Account
   * @validationRule Required for create/update operations
   */
  account: Pick<Account, 'id' | 'name1'>;
  /**
   * @displayName Blocker
   */
  blocker?: string;
  /**
   * @displayName Closed On
   */
  closedon?: string;
  /**
   * @displayName Confidence
   */
  confidence?: number;
  /**
   * @displayName Confidence Trend
   */
  confidenceTrend?: string;
  /**
   * @displayName Created On
   */
  createdon?: string;
  /**
   * @displayName Expected Close Date
   */
  expectedclosedate?: string;
  /**
   * @displayName Last Action
   */
  lastaction?: string;
  /**
   * @displayName Owner ID
   * @validationRule Required for create/update operations
   */
  ownerid: string;
  /**
   * @displayName Stage
   * @validationRule Required for create/update operations
   */
  stage: string;
  /**
   * @displayName Total Amount
   * @description Amount in the opportunity's own transaction currency.
   * @validationRule Required for create/update operations
   */
  totalamount: number;
  /**
   * @displayName Amount (Base Currency)
   * @description Dataverse-computed value of the amount in the environment base currency. Read-only.
   */
  amountBase?: number;
  /**
   * @displayName Transaction Currency Id
   * @description GUID of the opportunity's transaction currency (transactioncurrency record).
   */
  currencyId?: string;
  /**
   * @displayName Transaction Currency Name
   * @description Display name of the opportunity's transaction currency (e.g. "US Dollar").
   */
  currencyName?: string;
}

export const _Opportunity = 'Opportunity' as const;